// Configurações
const SUPABASE_URL = 'SUA_SUPABASE_URL';
const SUPABASE_KEY = 'SUA_SUPABASE_KEY';
const CLINIC_ID = 'SEU_CLINIC_ID';
const DRA_SARAH_ID = 'ID_DRA_SARAH';
const DRA_AMANDA_ID = 'ID_DRA_AMANDA';

// Parser de data flexível
function parseData(input) {
  const hoje = new Date();
  const ano = hoje.getFullYear();
  const mes = hoje.getMonth();
  const dia = hoje.getDate();

  const texto = String(input).toLowerCase().trim();

  if (texto === 'hoje') return hoje;
  if (texto === 'amanhã' || texto === 'amanha') return new Date(ano, mes, dia + 1);

  const diasSemana = {
    'domingo': 0, 'segunda': 1, 'terca': 2, 'terça': 2,
    'quarta': 3, 'quinta': 4, 'sexta': 5, 'sabado': 6, 'sábado': 6
  };

  for (const [nome, diaSem] of Object.entries(diasSemana)) {
    if (texto.includes(nome)) {
      const d = new Date(ano, mes, dia);
      const diff = (diaSem - d.getDay() + 7) % 7 || 7;
      d.setDate(d.getDate() + diff);
      return d;
    }
  }

  // DD/MM/YYYY ou DD/MM
  const matchBarra = texto.match(/(\d{1,2})\/(\d{1,2})(?:\/(\d{2,4}))?/);
  if (matchBarra) {
    let [_, d, m, a] = matchBarra;
    a = a ? (a.length === 2 ? '20' + a : a) : ano;
    return new Date(parseInt(a), parseInt(m) - 1, parseInt(d));
  }

  // YYYY-MM-DD
  const matchISO = texto.match(/(\d{4})-(\d{2})-(\d{2})/);
  if (matchISO) {
    const [_, a, m, d] = matchISO;
    return new Date(parseInt(a), parseInt(m) - 1, parseInt(d));
  }

  // "dia 17"
  const matchDia = texto.match(/(?:dia\s+)?(\d{1,2})/);
  if (matchDia) {
    return new Date(ano, mes, parseInt(matchDia[1]));
  }

  return null;
}

// Pegar input
const input = $input.item.json.query || $input.item.json.data || $input.item.json;
let dataParam = typeof input === 'string' ? input : (input.data || input.date || 'hoje');

const dataObj = parseData(dataParam);

if (!dataObj || isNaN(dataObj.getTime())) {
  return { response: `Não entendi a data "${dataParam}". Pode ser: "hoje", "amanhã", "segunda", "15/04"` };
}

const diaSemana = dataObj.getDay();
const diaNum = dataObj.getDate();
const mesNum = dataObj.getMonth();
const anoNum = dataObj.getFullYear();
const dateStr = `${anoNum}-${String(mesNum+1).padStart(2,'0')}-${String(diaNum).padStart(2,'0')}`;

const diasPtBr = ['domingo', 'segunda', 'terça', 'quarta', 'quinta', 'sexta', 'sábado'];

if (diaSemana === 0 || diaSemana === 6) {
  return { response: `${diasPtBr[diaSemana]}, ${diaNum}/${mesNum+1} é fim de semana. A clínica funciona segunda a sexta.` };
}

// Horários das profissionais
const HORARIOS_SARAH = {
  1: ['13:30', '14:00', '14:30', '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00', '18:30'],
  2: ['09:00', '09:30', '10:00', '10:30', '11:00', '11:30'],
  3: ['13:30', '14:00', '14:30', '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00', '18:30'],
  4: [],
  5: ['13:30', '14:00', '14:30', '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00', '18:30'],
};

const HORARIOS_AMANDA = {
  1: ['09:00', '09:30', '10:00', '10:30', '11:00', '11:30', '13:30', '14:00', '14:30', '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00', '18:30'],
  2: ['09:00', '09:30', '10:00', '10:30', '11:00', '11:30', '13:30', '14:00', '14:30', '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00', '18:30'],
  3: ['09:00', '09:30', '10:00', '10:30', '11:00', '11:30', '13:30', '14:00', '14:30', '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00', '18:30'],
  4: ['09:00', '09:30', '10:00', '10:30', '11:00', '11:30', '13:30', '14:00', '14:30', '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00', '18:30'],
  5: ['09:00', '09:30', '10:00', '10:30', '11:00', '11:30', '13:30', '14:00', '14:30', '15:00', '15:30', '16:00', '16:30', '17:00', '17:30', '18:00', '18:30'],
};

// Buscar ocupados
let ocupados = [];
try {
  const response = await this.helpers.httpRequest({
    method: 'GET',
    url: `${SUPABASE_URL}/rest/v1/appointments?clinic_id=eq.${CLINIC_ID}&start_time=gte.${dateStr}T00:00:00&start_time=lte.${dateStr}T23:59:59&status=neq.cancelled`,
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
  });
  ocupados = response || [];
} catch (e) {}

const extrairHora = (s) => { const m = s.match(/T(\d{2}:\d{2})/); return m ? m[1] : null; };

const ocupSarah = ocupados.filter(a => a.professional_id === DRA_SARAH_ID).map(a => extrairHora(a.start_time)).filter(h => h);
const ocupAmanda = ocupados.filter(a => a.professional_id === DRA_AMANDA_ID).map(a => extrairHora(a.start_time)).filter(h => h);

const dispSarah = (HORARIOS_SARAH[diaSemana] || []).filter(h => !ocupSarah.includes(h));
const dispAmanda = (HORARIOS_AMANDA[diaSemana] || []).filter(h => !ocupAmanda.includes(h));

let resp = `HORÁRIOS ${diasPtBr[diaSemana].toUpperCase()} ${diaNum}/${mesNum+1}:\n\n`;

if (diaSemana === 4) {
  resp += `Dra. Sarah: não atende quinta\n`;
} else if (dispSarah.length === 0) {
  resp += `Dra. Sarah: sem horário\n`;
} else {
  resp += `Dra. Sarah: ${dispSarah.slice(0,4).join(', ')}\n`;
}

if (dispAmanda.length === 0) {
  resp += `Dra. Amanda: sem horário`;
} else {
  resp += `Dra. Amanda: ${dispAmanda.slice(0,4).join(', ')}`;
}

resp += `\n\nOFEREÇA MÁXIMO 2 HORÁRIOS. Priorize Dra. Amanda.`;

return { response: resp };

