const SUPABASE_KEY = 'SUA_SUPABASE_KEY';
const CLINIC_ID = 'SEU_CLINIC_ID';
const DRA_SARAH_ID = 'ID_DRA_SARAH';
const DRA_AMANDA_ID = 'ID_DRA_AMANDA';

const input = $input.item.json.query || $input.item.json;
let params;
try {
  params = typeof input === 'string' ? JSON.parse(input) : input;
} catch (e) {
  params = input;
}

const data = params.data || params.date;
const horario = params.horario || params.time || params.hora;
const profissional = params.profissional || params.professional || 'amanda';
const nomeCompleto = params.nome_completo || params.nome || params.name;

if (!data || !horario) {
  return { response: 'ERRO: Preciso da data (YYYY-MM-DD) e horário (HH:MM) para agendar.' };
}

if (!nomeCompleto || nomeCompleto.length < 5 || nomeCompleto.toLowerCase().includes('lead')) {
  return { response: 'ERRO: Preciso do NOME COMPLETO do paciente para agendar. Pergunte: "Me passa seu nome completo para confirmar?"' };
}

const professionalId = profissional.toLowerCase().includes('sarah') ? DRA_SARAH_ID : DRA_AMANDA_ID;
const professionalName = profissional.toLowerCase().includes('sarah') ? 'Dra. Sarah' : 'Dra. Amanda';

