  const diasPtBr = ['domingo', 'segunda-feira', 'terça-feira', 'quarta-feira', 'quinta-feira', 'sexta-feira', 'sábado'];
  const dataObj = new Date(data + 'T12:00:00');
  const diaSemana = diasPtBr[dataObj.getDay()];
  const dataFormatada = `${dataObj.getDate().toString().padStart(2,'0')}/${(dataObj.getMonth()+1).toString().padStart(2,'0')}/${dataObj.getFullYear()}`;

  return { 
    response: `AGENDAMENTO CONFIRMADO!\n\nPaciente: ${nomeCompleto}\nData: ${diaSemana}, ${dataFormatada}\nHorário: ${horario}\nProfissional: ${professionalName}\n\nAgora envie a mensagem de confirmação padronizada ao paciente.`
  };

} catch (e) {
  return { response: `ERRO ao criar agendamento: ${e.message}. Tente novamente.` };
}

