let answer = $input.first().json.text || $input.first().json.content || $input.first().json.output || '';

// Remover prefixos comuns
answer = answer.replace(/^(Donna:|Eva:|Assistente:|Assistant:)/gi, '').trim();

// Remover marcadores de código
answer = answer.replace(/```[\s\S]*?```/g, '').trim();

// Remover \n literais e substituir por quebras reais
answer = answer.replace(/\\n/g, '\n');

// Limitar tamanho
if (answer.length > 1500) {
  answer = answer.substring(0, 1500) + '...';
}

return {
  answer,
  phone: $('Carregar Histórico').first().json.phone,
  conversationHistory: $('Carregar Histórico').first().json.conversationHistory,
