const SUPABASE_URL = 'SUA_SUPABASE_URL';
const SUPABASE_KEY = 'SUA_SUPABASE_KEY';

const phone = $input.first().json.phone;
const clinicId = $input.first().json.clinicId;
const customerName = $input.first().json.customerName;
const answer = $input.first().json.answer;
let conversationHistory = $input.first().json.conversationHistory || [];

// Adicionar resposta da IA ao histórico
conversationHistory.push({
  role: 'assistant',
  content: answer,
  timestamp: new Date().toISOString()
});

// Limitar a 50 mensagens
if (conversationHistory.length > 50) {
  conversationHistory = conversationHistory.slice(-50);
}

try {
  // Verificar se conversa existe
  const existing = await fetch(
    `${SUPABASE_URL}/rest/v1/eva_conversations?phone=eq.${phone}&clinic_id=eq.${clinicId}&select=id`,
    {
      headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}` }
    }
  );
  const convs = await existing.json();

  const convData = {
    clinic_id: clinicId,
    phone: phone,
    customer_name: customerName,
    messages: conversationHistory,
    updated_at: new Date().toISOString()
  };

  if (convs && convs.length > 0) {
    // Atualizar
    await fetch(
      `${SUPABASE_URL}/rest/v1/eva_conversations?id=eq.${convs[0].id}`,
      {
        method: 'PATCH',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(convData)
      }
    );
  } else {
    // Criar
    await fetch(
      `${SUPABASE_URL}/rest/v1/eva_conversations`,
      {
        method: 'POST',
        headers: { 'apikey': SUPABASE_KEY, 'Authorization': `Bearer ${SUPABASE_KEY}`, 'Content-Type': 'application/json' },
        body: JSON.stringify(convData)
      }
    );
  }
} catch (e) {
  console.error('Erro ao salvar conversa:', e);
}

return {
  answer,
  phone
};
